{
  "workflow_id": "wf_7x9kL2pQ",
  "name": "Auto-track client inquiries",
  "description": "Automatically logs new client inquiries from Prospect Partners into the Client Tracker spreadsheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": "@prospectpartners.com",
      "subject_filter": "New Client Inquiry",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Extract inquiry details",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          {
            "name": "sender_email",
            "pattern": "from"
          },
          {
            "name": "subject",
            "pattern": "subject"
          },
          {
            "name": "amount",
            "pattern": "regex",
            "regex": "\\$([0-9,]+)"
          }
        ]
      },
      "output_variable": "inquiry_data"
    },
    {
      "id": "step_2",
      "name": "Log to spreadsheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Inquiries",
        "row_data": [
          "{{inquiry_data.sender_email}}",
          "{{inquiry_data.subject}}",
          "{{inquiry_data.amount}}",
          "{{workflow.run_timestamp}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 15,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_8d2f9a7c",
  "name": "Weekly Overdue Invoice Summary",
  "description": "Automatically compiles overdue invoices from a Google Sheet and emails a formatted summary to the finance team every Friday.",
  "created_from_transcript": true,
  "trigger": {
    "type": "manual",
    "config": {}
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Read overdue invoices from sheet",
      "action": "sheets.read_rows",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Overdue",
        "range": "A:D"
      },
      "output_variable": "overdue_invoices"
    },
    {
      "id": "step_2",
      "name": "Format email body",
      "action": "gmail.send_email",
      "config": {
        "to": "finance-team@company.com",
        "cc": "sarah@company.com",
        "subject": "Weekly Overdue Invoices \u2013 {{workflow.run_timestamp}}",
        "body": "Here are the overdue invoices as of {{workflow.run_timestamp}}:\n\n<table><tr><th>Client</th><th>Invoice #</th><th><b>Amount</b></th><th>Due Date</th></tr>{{#overdue_invoices}}<tr><td>{{client_name}}</td><td>{{invoice_number}}</td><td><b>{{amount}}</b></td><td>{{due_date}}</td></tr>{{/overdue_invoices}}</table>"
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 60,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

