{
  "workflow_id": "wf_7x9k2pq4",
  "name": "Urgent Customer Email Triage",
  "description": "Automatically forwards urgent customer emails to the team lead and logs them in a Google Sheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": null,
      "subject_filter": "URGENT,Payment Failed",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check sender for VIP clients",
      "action": "condition",
      "config": {
        "if": "{{trigger.from}} contains '@acme.com' OR {{trigger.from}} contains '@globex.com'",
        "then": "step_3",
        "else": "step_2"
      }
    },
    {
      "id": "step_2",
      "name": "Check if email is urgent by subject",
      "action": "condition",
      "config": {
        "if": "{{trigger.subject}} contains 'URGENT' OR {{trigger.subject}} contains 'Payment Failed'",
        "then": "step_3",
        "else": "end"
      }
    },
    {
      "id": "step_3",
      "name": "Forward email to Mark and Slack channel",
      "action": "gmail.send_email",
      "config": {
        "to": [
          "mark@company.com",
          "support-slack-channel@company.com"
        ],
        "subject": "URGENT: {{trigger.subject}} (from {{trigger.from}})",
        "body": "This email requires immediate attention:\n\nFrom: {{trigger.from}}\nSubject: {{trigger.subject}}\n\n{{trigger.body}}"
      }
    },
    {
      "id": "step_4",
      "name": "Log urgent request in Google Sheet",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Urgent Requests",
        "row_data": [
          "{{workflow.run_timestamp}}",
          "{{trigger.from}}",
          "{{trigger.subject}}"
        ]
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 30,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_7x9k2p4m",
  "name": "Auto-confirm supplier invoices/quotes",
  "description": "Automatically sends a confirmation reply to supplier emails containing invoices or quotes.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": [
        "acme.com",
        "globalsupplies.com",
        "techparts.net"
      ],
      "subject_filter": [
        "Invoice",
        "Quote"
      ],
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Extract invoice/quote number from subject",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          {
            "field_name": "subject_number",
            "pattern": "(Invoice|Quote)\\s*#?([A-Za-z0-9-]+)",
            "group": 2
          }
        ]
      },
      "output_variable": "subject_number"
    },
    {
      "id": "step_2",
      "name": "Send confirmation reply",
      "action": "gmail.send_email",
      "config": {
        "to": "{{trigger.from}}",
        "subject": "Re: {{trigger.subject}}",
        "body": "Hi there,\n\nThanks for sending this over! We\u2019ve received your {{trigger.subject | lower | contains:'invoice' ? 'invoice' : 'quote'}} (Ref: {{subject_number}}) and will review it shortly. Let us know if you need anything else.\n\nBest regards,\nNatalie"
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 30,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

{
  "workflow_id": "wf_7x9k2pLm",
  "name": "Contractor Invoice Triage",
  "description": "Automatically routes contractor invoices to the correct recipient or logs them in a spreadsheet.",
  "created_from_transcript": true,
  "trigger": {
    "type": "email_received",
    "config": {
      "from_filter": null,
      "subject_filter": "invoice",
      "match": "contains"
    }
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Check contractor email",
      "action": "gmail.read_email",
      "config": {
        "extract_fields": [
          "from",
          "subject",
          "body"
        ]
      },
      "output_variable": "email_data"
    },
    {
      "id": "step_2",
      "name": "Route Acme Design invoices",
      "action": "condition",
      "config": {
        "if": "{{email_data.from}} == 'Acme Design'",
        "then": "step_3",
        "else": "step_4"
      }
    },
    {
      "id": "step_3",
      "name": "Forward to Sarah",
      "action": "gmail.send_email",
      "config": {
        "to": "sarah@ourcompany.com",
        "subject": "Automated forward: invoice for your review - {{email_data.subject}}",
        "body": "FYI, this invoice is for your review.\n\nOriginal email:\nFrom: {{email_data.from}}\nSubject: {{email_data.subject}}\n\n{{email_data.body}}"
      }
    },
    {
      "id": "step_4",
      "name": "Route Bright Solutions invoices",
      "action": "condition",
      "config": {
        "if": "{{email_data.from}} == 'Bright Solutions'",
        "then": "step_5",
        "else": "step_6"
      }
    },
    {
      "id": "step_5",
      "name": "Forward to Tom",
      "action": "gmail.send_email",
      "config": {
        "to": "tom@ourcompany.com",
        "subject": "Automated forward: invoice for your review - {{email_data.subject}}",
        "body": "FYI, this invoice is for your review.\n\nOriginal email:\nFrom: {{email_data.from}}\nSubject: {{email_data.subject}}\n\n{{email_data.body}}"
      }
    },
    {
      "id": "step_6",
      "name": "Route QuickBuild invoices",
      "action": "condition",
      "config": {
        "if": "{{email_data.from}} == 'QuickBuild'",
        "then": "step_7",
        "else": "step_9"
      }
    },
    {
      "id": "step_7",
      "name": "Log QuickBuild invoice",
      "action": "sheets.append_row",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "QuickBuild",
        "row_data": [
          "{{workflow.run_timestamp}}",
          "{{email_data.subject}}",
          "{{email_data.body}}"
        ]
      }
    },
    {
      "id": "step_8",
      "name": "Reply to QuickBuild",
      "action": "gmail.send_email",
      "config": {
        "to": "{{email_data.from}}",
        "subject": "Re: {{email_data.subject}}",
        "body": "Hi,\n\nWe\u2019ve received your invoice and logged it in our system. Thank you!\n\nBest,\nNatalie"
      }
    },
    {
      "id": "step_9",
      "name": "Forward to accounting",
      "action": "gmail.send_email",
      "config": {
        "to": "accounting@ourcompany.com",
        "subject": "New contractor invoice - {{email_data.subject}}",
        "body": "FYI, this is a new contractor invoice that needs to be set up in the system.\n\nOriginal email:\nFrom: {{email_data.from}}\nSubject: {{email_data.subject}}\n\n{{email_data.body}}"
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 30,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

