{
  "workflow_id": "wf_7x9kLm2p",
  "name": "Weekly Sales Recap Email",
  "description": "Automatically pulls new sales entries from the weekly tracker and emails a recap to the team every Friday.",
  "created_from_transcript": true,
  "trigger": {
    "type": "manual",
    "config": {}
  },
  "steps": [
    {
      "id": "step_1",
      "name": "Read new sales entries",
      "action": "sheets.read_rows",
      "config": {
        "spreadsheet_id": "{{user.spreadsheet_id}}",
        "sheet_name": "Weekly Sales Tracker",
        "range": "A:E"
      },
      "output_variable": "new_entries"
    },
    {
      "id": "step_2",
      "name": "Filter this week's entries",
      "action": "condition",
