        "else": "skip"
      }
    },
    {
      "id": "step_3",
      "name": "Format email body",
      "action": "gmail.send_email",
      "config": {
        "to": [
          "sales-team@company.com",
          "manager@company.com"
        ],
        "subject": "Weekly Sales Recap \u2013 {{workflow.run_timestamp | date_range_week}}",
        "body": "Hi team,\n\nHere\u2019s what came in this week:\n\n<table>{{new_entries | format_as_table}}</table>\n\nLet me know if you have any questions!\n\nBest,\nNatalie"
      }
    }
  ],
  "meta": {
    "estimated_time_saved_minutes": 20,
    "runs": 0,
    "last_run": null,
    "status": "active"
  }
}

